      'dances_shop_vbmax': dancesShopVbmax,
      'gliders_shop_vbmin': glidersShopVbmin,
      'gliders_shop_vbmax': glidersShopVbmax,
      'bp': bp?.value,
      'lmin': lmin,
      'lmax': lmax,
      'bp_lmin': bpLmin,
      'bp_lmax': bpLmax,
      'last_trans_date': lastTransDate,
