class CategoryEaParams {
  /// The number of the page to display results from.
  final int? page;

  /// Minimal price of account (Inclusive).
  final int? pmin;

  /// Maximum price of account (Inclusive).
  final int? pmax;

  /// The word or words contained in the account title.
  final String? title;
  final OrderBy? orderBy;

  /// List of tag ids (Tag list is available via $1).
  final List<int>? tagId;

  /// List of tag ids that won't be included (Tag list is available via $1).
  final List<int>? notTagId;

  /// List of tag ids (Tag list is available via $1).
  final List<int>? publicTagId;

  /// List of tag ids that won't be included (Tag list is available via $1).
  final List<int>? notPublicTagId;
  final Origin? origin;

  /// List of account origins that won't be included.
  final List<String>? notOrigin;

  /// Search accounts of user.
  final int? userId;

  /// Not sold before.
  final bool? nsb;

  /// Sold before.
  final bool? sb;

  /// Not sold by me before.
  final bool? nsbByMe;

  /// Sold by me before.
  final bool? sbByMe;
  final Currency? currency;

  /// Has email login data.
  final bool? emailLoginData;

  /// Email provider.
  final List<String>? emailProvider;
  final NotEmailProvider? notEmailProvider;

  /// Parse same item ids.
  final bool? parseSameItemIds;

  /// Email type.
  final List<String>? emailType;

  /// Domain of native/autoreg email.
  final String? itemDomain;

  /// List of games.
  final List<String>? game;

  /// List of allowed countries.
  final List<String>? country;

  /// List of disallowed countries.
  final List<String>? notCountry;

  /// Minimum count of games.
  final int? gmin;

  /// Maximum count of games.
  final int? gmax;

  /// Minimum rank points in Apex Legends.
  final int? alRankMin;

  /// Maximum rank points in Apex Legends.
  final int? alRankMax;

  /// Minimum level in Apex Legends.
  final int? alLevelMin;

  /// Maximum level in Apex Legends.
  final int? alLevelMax;
  final HasBan? hasBan;
  final XboxConnected? xboxConnected;
  final SteamConnected? steamConnected;
  final PsnConnected? psnConnected;
  final Subscription? subscription;

  /// Length of subscription.
  final int? subscriptionLength;
  final SubscriptionPeriod? subscriptionPeriod;

  /// List of minimum hours played by game.
  final Map<String, int>? hoursPlayed;

  /// List of maximum hours played by game.
  final Map<String, int>? hoursPlayedMax;
  final Transactions? transactions;

  const CategoryEaParams({
    this.page,
    this.pmin,
    this.pmax,
    this.title,
    this.orderBy,
    this.tagId,
    this.notTagId,
    this.publicTagId,
    this.notPublicTagId,
    this.origin,
    this.notOrigin,
    this.userId,
    this.nsb,
    this.sb,
    this.nsbByMe,
    this.sbByMe,
    this.currency,
    this.emailLoginData,
    this.emailProvider,
    this.notEmailProvider,
    this.parseSameItemIds,
    this.emailType,
    this.itemDomain,
    this.game,
    this.country,
    this.notCountry,
    this.gmin,
    this.gmax,
    this.alRankMin,
    this.alRankMax,
    this.alLevelMin,
    this.alLevelMax,
    this.hasBan,
    this.xboxConnected,
    this.steamConnected,
    this.psnConnected,
    this.subscription,
    this.subscriptionLength,
    this.subscriptionPeriod,
    this.hoursPlayed,
    this.hoursPlayedMax,
    this.transactions,
  });

  Map<String, Object?> toMap() {
    return {
      'page': page,
      'pmin': pmin,
      'pmax': pmax,
      'title': title,
      'order_by': orderBy?.value,
      'tag_id[]': tagId,
      'not_tag_id[]': notTagId,
      'public_tag_id[]': publicTagId,
      'not_public_tag_id[]': notPublicTagId,
      'origin[]': origin?.value,
      'not_origin[]': notOrigin,
      'user_id': userId,
      'nsb': nsb,
      'sb': sb,
      'nsb_by_me': nsbByMe,
      'sb_by_me': sbByMe,
      'currency': currency?.value,
      'email_login_data': emailLoginData,
      'email_provider[]': emailProvider,
      'not_email_provider[]': notEmailProvider?.value,
      'parse_same_item_ids': parseSameItemIds,
      'email_type[]': emailType,
      'item_domain': itemDomain,
      'game[]': game,
      'country[]': country,
      'not_country[]': notCountry,
      'gmin': gmin,
      'gmax': gmax,
      'al_rank_min': alRankMin,
      'al_rank_max': alRankMax,
      'al_level_min': alLevelMin,
      'al_level_max': alLevelMax,
      'has_ban': hasBan?.value,
      'xbox_connected': xboxConnected?.value,
      'steam_connected': steamConnected?.value,
      'psn_connected': psnConnected?.value,
      'subscription': subscription?.value,
      'subscription_length': subscriptionLength,
      'subscription_period': subscriptionPeriod?.value,
      'hours_played': hoursPlayed,
      'hours_played_max': hoursPlayedMax,
      'transactions': transactions?.value,
    };
  }
}

