class CategoryWotParams {
  /// The number of the page to display results from.
  final int? page;

  /// Minimal price of account (Inclusive).
  final int? pmin;

  /// Maximum price of account (Inclusive).
  final int? pmax;

  /// The word or words contained in the account title.
  final String? title;
  final OrderBy? orderBy;

  /// List of tag ids (Tag list is available via $1).
  final List<int>? tagId;

  /// List of tag ids that won't be included (Tag list is available via $1).
  final List<int>? notTagId;

  /// List of tag ids (Tag list is available via $1).
  final List<int>? publicTagId;

  /// List of tag ids that won't be included (Tag list is available via $1).
  final List<int>? notPublicTagId;
  final Origin? origin;

  /// List of account origins that won't be included.
  final List<String>? notOrigin;

  /// Search accounts of user.
  final int? userId;

  /// Not sold before.
  final bool? nsb;

  /// Sold before.
  final bool? sb;

  /// Not sold by me before.
  final bool? nsbByMe;

  /// Sold by me before.
  final bool? sbByMe;
  final Currency? currency;

  /// Has email login data.
  final bool? emailLoginData;

  /// Email provider.
  final List<String>? emailProvider;
  final NotEmailProvider? notEmailProvider;

  /// Parse same item ids.
  final bool? parseSameItemIds;

  /// Email type.
  final List<String>? emailType;

  /// Domain of native/autoreg email.
  final String? itemDomain;
  final Tel? tel;

  /// Number of days the account has been offline.
  final int? daybreak;

  /// Minimum number of battles.
  final int? battlesMin;

  /// Maximum number of battles.
  final int? battlesMax;

  /// Minimum number of gold.
  final int? goldMin;

  /// Maximum number of gold.
  final int? goldMax;

  /// Minimum number of silver.
  final int? silverMin;

  /// Maximum number of silver.
  final int? silverMax;

  /// Minimum number of top tanks.
  final int? topMin;

  /// Maximum number of top tanks.
  final int? topMax;

  /// Minimum number of premium tanks.
  final int? premMin;

  /// Maximum number of premium tanks.
  final int? premMax;

  /// Minimum number of top premium tanks.
  final int? topPremMin;

  /// Maximum number of top premium tanks.
  final int? topPremMax;

  /// Minimum number of wins.
  final int? winPmin;

  /// Maximum number of wins.
  final int? winPmax;

  /// List of tanks.
  final List<int>? tank;

  /// Region.
  final List<String>? region;

  /// Exclude region.
  final List<String>? notRegion;
  final Premium? premium;

  /// When premium subscription will be active.
  final int? premiumExpiration;
  final PremiumExpirationPeriod? premiumExpirationPeriod;
  final Clan? clan;

  /// List of allowed clan role.
  final List<String>? clanRole;

  /// List of disallowed clan role.
  final List<String>? notClanRole;

  /// Minimum number of gold in clan treasure.
  final int? clanGoldMin;

  /// Maximum number of gold in clan treasure.
  final int? clanGoldMax;

  /// Minimum number of credits in clan treasure.
  final int? clanCreditsMin;

  /// Maximum number of credits in clan treasure.
  final int? clanCreditsMax;

  /// Minimum number of crystal in clan treasure.
  final int? clanCrystalMin;

  /// Maximum number of crystal in clan treasure.
  final int? clanCrystalMax;

  /// List of allowed countries.
  final List<String>? country;

  /// List of disallowed countries.
  final List<String>? notCountry;

  const CategoryWotParams({
    this.page,
    this.pmin,
    this.pmax,
    this.title,
    this.orderBy,
    this.tagId,
    this.notTagId,
    this.publicTagId,
    this.notPublicTagId,
    this.origin,
    this.notOrigin,
    this.userId,
    this.nsb,
    this.sb,
    this.nsbByMe,
    this.sbByMe,
    this.currency,
    this.emailLoginData,
    this.emailProvider,
    this.notEmailProvider,
    this.parseSameItemIds,
    this.emailType,
    this.itemDomain,
    this.tel,
    this.daybreak,
    this.battlesMin,
    this.battlesMax,
    this.goldMin,
    this.goldMax,
    this.silverMin,
    this.silverMax,
    this.topMin,
    this.topMax,
    this.premMin,
    this.premMax,
    this.topPremMin,
    this.topPremMax,
    this.winPmin,
    this.winPmax,
    this.tank,
    this.region,
    this.notRegion,
    this.premium,
    this.premiumExpiration,
    this.premiumExpirationPeriod,
    this.clan,
    this.clanRole,
    this.notClanRole,
    this.clanGoldMin,
    this.clanGoldMax,
    this.clanCreditsMin,
    this.clanCreditsMax,
    this.clanCrystalMin,
    this.clanCrystalMax,
    this.country,
    this.notCountry,
  });

  Map<String, Object?> toMap() {
    return {
      'page': page,
      'pmin': pmin,
      'pmax': pmax,
      'title': title,
      'order_by': orderBy?.value,
      'tag_id[]': tagId,
      'not_tag_id[]': notTagId,
      'public_tag_id[]': publicTagId,
      'not_public_tag_id[]': notPublicTagId,
      'origin[]': origin?.value,
      'not_origin[]': notOrigin,
      'user_id': userId,
      'nsb': nsb,
      'sb': sb,
      'nsb_by_me': nsbByMe,
      'sb_by_me': sbByMe,
      'currency': currency?.value,
      'email_login_data': emailLoginData,
      'email_provider[]': emailProvider,
      'not_email_provider[]': notEmailProvider?.value,
      'parse_same_item_ids': parseSameItemIds,
      'email_type[]': emailType,
      'item_domain': itemDomain,
      'tel': tel?.value,
      'daybreak': daybreak,
      'battles_min': battlesMin,
      'battles_max': battlesMax,
      'gold_min': goldMin,
      'gold_max': goldMax,
      'silver_min': silverMin,
      'silver_max': silverMax,
      'top_min': topMin,
      'top_max': topMax,
      'prem_min': premMin,
      'prem_max': premMax,
      'top_prem_min': topPremMin,
      'top_prem_max': topPremMax,
      'win_pmin': winPmin,
      'win_pmax': winPmax,
      'tank[]': tank,
      'region[]': region,
      'not_region[]': notRegion,
      'premium': premium?.value,
      'premium_expiration': premiumExpiration,
      'premium_expiration_period': premiumExpirationPeriod?.value,
      'clan': clan?.value,
      'clan_role[]': clanRole,
      'not_clan_role[]': notClanRole,
      'clan_gold_min': clanGoldMin,
      'clan_gold_max': clanGoldMax,
      'clan_credits_min': clanCreditsMin,
      'clan_credits_max': clanCreditsMax,
      'clan_crystal_min': clanCrystalMin,
      'clan_crystal_max': clanCrystalMax,
      'country[]': country,
      'not_country[]': notCountry,
    };
  }
}

class CategoryWotResponseItemsBumpSettings {
  final bool canBumpItem;
  final bool canBumpItemGlobally;
  final dynamic shortErrorPhrase;
  final dynamic errorPhrase;

  const CategoryWotResponseItemsBumpSettings({
    required this.canBumpItem,
    required this.canBumpItemGlobally,
    required this.shortErrorPhrase,
    required this.errorPhrase,
  });

  factory CategoryWotResponseItemsBumpSettings.fromJson(
          Map<String, dynamic> json) =>
      CategoryWotResponseItemsBumpSettings(
        canBumpItem:
            json['canBumpItem'] is bool ? json['canBumpItem'] as bool : false,
        canBumpItemGlobally: json['canBumpItemGlobally'] is bool
            ? json['canBumpItemGlobally'] as bool
            : false,
        shortErrorPhrase: json['shortErrorPhrase'],
        errorPhrase: json['errorPhrase'],
      );
}

