class CategorySocialClubParams {
  /// The number of the page to display results from.
  final int? page;

  /// Minimal price of account (Inclusive).
  final int? pmin;

  /// Maximum price of account (Inclusive).
  final int? pmax;

  /// The word or words contained in the account title.
  final String? title;
  final OrderBy? orderBy;

  /// List of tag ids (Tag list is available via $1).
  final List<int>? tagId;

  /// List of tag ids that won't be included (Tag list is available via $1).
  final List<int>? notTagId;

  /// List of tag ids (Tag list is available via $1).
  final List<int>? publicTagId;

  /// List of tag ids that won't be included (Tag list is available via $1).
  final List<int>? notPublicTagId;
  final Origin? origin;

  /// List of account origins that won't be included.
  final List<String>? notOrigin;

  /// Search accounts of user.
  final int? userId;

  /// Not sold before.
  final bool? nsb;

  /// Sold before.
  final bool? sb;

  /// Not sold by me before.
  final bool? nsbByMe;

  /// Sold by me before.
  final bool? sbByMe;
  final Currency? currency;

  /// Has email login data.
  final bool? emailLoginData;

  /// Email provider.
  final List<String>? emailProvider;
  final NotEmailProvider? notEmailProvider;

  /// Parse same item ids.
  final bool? parseSameItemIds;

  /// Number of days the account has been offline.
  final int? daybreak;

  /// Minimum number of Social Club level.
  final int? levelMin;

  /// Maximum number of Social Club level.
  final int? levelMax;

  /// Minimum number of GTA V cash.
  final int? cashMin;

  /// Maximum number of GTA V cash.
  final int? cashMax;

  /// Minimum number of GTA V bank cash.
  final int? bankCashMin;

  /// Maximum number of GTA V bank cash.
  final int? bankCashMax;

  /// List of games.
  final List<String>? game;

  const CategorySocialClubParams({
    this.page,
    this.pmin,
    this.pmax,
    this.title,
    this.orderBy,
    this.tagId,
    this.notTagId,
    this.publicTagId,
    this.notPublicTagId,
    this.origin,
    this.notOrigin,
    this.userId,
    this.nsb,
    this.sb,
    this.nsbByMe,
    this.sbByMe,
    this.currency,
    this.emailLoginData,
    this.emailProvider,
    this.notEmailProvider,
    this.parseSameItemIds,
    this.daybreak,
    this.levelMin,
    this.levelMax,
    this.cashMin,
    this.cashMax,
    this.bankCashMin,
    this.bankCashMax,
    this.game,
  });

  Map<String, Object?> toMap() {
    return {
      'page': page,
      'pmin': pmin,
      'pmax': pmax,
      'title': title,
      'order_by': orderBy?.value,
      'tag_id[]': tagId,
      'not_tag_id[]': notTagId,
      'public_tag_id[]': publicTagId,
      'not_public_tag_id[]': notPublicTagId,
      'origin[]': origin?.value,
      'not_origin[]': notOrigin,
      'user_id': userId,
      'nsb': nsb,
      'sb': sb,
      'nsb_by_me': nsbByMe,
      'sb_by_me': sbByMe,
      'currency': currency?.value,
      'email_login_data': emailLoginData,
      'email_provider[]': emailProvider,
      'not_email_provider[]': notEmailProvider?.value,
      'parse_same_item_ids': parseSameItemIds,
      'daybreak': daybreak,
      'level_min': levelMin,
      'level_max': levelMax,
      'cash_min': cashMin,
      'cash_max': cashMax,
      'bank_cash_min': bankCashMin,
      'bank_cash_max': bankCashMax,
      'game[]': game,
    };
  }
}

