  final int? daybreak;

  /// Minimum count of games.
  final int? gmin;

  /// Maximum count of games.
  final int? gmax;
  final Subscription? subscription;

  /// Length of subscription.
  final int? subscriptionLength;
  final SubscriptionPeriod? subscriptionPeriod;

