  final int? r6LevelMin;

  /// Maximum level in Tom Clancy's Rainbow Six Siege.
  final int? r6LevelMax;

  /// Minimum rank points in Tom Clancy's Rainbow Six Siege.
  final int? r6RankMin;

  /// Maximum rank points in Tom Clancy's Rainbow Six Siege.
  final int? r6RankMax;

