    this.notCountry,
    this.daybreak,
    this.gmin,
    this.gmax,
    this.subscription,
    this.subscriptionLength,
    this.subscriptionPeriod,
    this.r6LevelMin,
    this.r6LevelMax,
    this.r6RankMin,
