    this.r6Smin,
    this.r6Smax,
    this.r6Skin,
    this.r6Operator,
    this.xboxConnected,
    this.psnConnected,
    this.steamConnected,
    this.balanceMin,
    this.balanceMax,
    this.transactions,
    this.reg,
    this.regPeriod,
