  const CategoryDiscordParams({
    this.page,
    this.pmin,
    this.pmax,
    this.title,
    this.orderBy,
    this.tagId,
    this.notTagId,
    this.publicTagId,
    this.notPublicTagId,
    this.origin,
    this.notOrigin,
    this.userId,
    this.nsb,
    this.sb,
    this.nsbByMe,
    this.sbByMe,
    this.currency,
    this.emailLoginData,
    this.emailProvider,
    this.notEmailProvider,
    this.parseSameItemIds,
    this.emailType,
    this.itemDomain,
    this.tel,
    this.nitro,
    this.nitroType,
    this.nitroLength,
    this.nitroPeriod,
    this.boostsMin,
    this.boostsMax,
    this.billing,
    this.gifts,
    this.transactions,
    this.badge,
    this.condition,
    this.chatMin,
    this.chatMax,
    this.minAdminMembers,
    this.maxAdminMembers,
    this.minAdmin,
    this.maxAdmin,
    this.reg,
