class CategoryTikTokParams {
  /// The number of the page to display results from.
  final int? page;

  /// Minimal price of account (Inclusive).
  final int? pmin;

  /// Maximum price of account (Inclusive).
  final int? pmax;

  /// The word or words contained in the account title.
  final String? title;
  final OrderBy? orderBy;

  /// List of tag ids (Tag list is available via $1).
  final List<int>? tagId;

  /// List of tag ids that won't be included (Tag list is available via $1).
  final List<int>? notTagId;

  /// List of tag ids (Tag list is available via $1).
  final List<int>? publicTagId;

  /// List of tag ids that won't be included (Tag list is available via $1).
  final List<int>? notPublicTagId;
  final Origin? origin;

  /// List of account origins that won't be included.
  final List<String>? notOrigin;

  /// Search accounts of user.
  final int? userId;

  /// Not sold before.
  final bool? nsb;

  /// Sold before.
  final bool? sb;

  /// Not sold by me before.
  final bool? nsbByMe;

  /// Sold by me before.
  final bool? sbByMe;
  final Currency? currency;

  /// Has email login data.
  final bool? emailLoginData;

  /// Email provider.
  final List<String>? emailProvider;
  final NotEmailProvider? notEmailProvider;

  /// Parse same item ids.
  final bool? parseSameItemIds;

  /// Email type.
  final List<String>? emailType;

  /// Domain of native/autoreg email.
  final String? itemDomain;
  final Tel? tel;

  /// How old is the account.
  final int? reg;
  final RegPeriod? regPeriod;

  /// Minimum number of followers.
  final int? followersMin;

  /// Maximum number of followers.
  final int? followersMax;

  /// Minimum number of posts.
  final int? postMin;

  /// Maximum number of posts.
  final int? postMax;

  /// Minimum number of likes.
  final int? likeMin;

  /// Maximum number of likes.
  final int? likeMax;

  /// Minimum number of coins.
  final int? coinsMin;

  /// Maximum number of coins.
  final int? coinsMax;
  final CookieLogin? cookieLogin;
  final Verified? verified;
  final Email? email;

  const CategoryTikTokParams({
    this.page,
    this.pmin,
    this.pmax,
    this.title,
    this.orderBy,
    this.tagId,
    this.notTagId,
    this.publicTagId,
    this.notPublicTagId,
    this.origin,
    this.notOrigin,
    this.userId,
    this.nsb,
    this.sb,
    this.nsbByMe,
    this.sbByMe,
    this.currency,
    this.emailLoginData,
    this.emailProvider,
    this.notEmailProvider,
    this.parseSameItemIds,
    this.emailType,
    this.itemDomain,
    this.tel,
    this.reg,
    this.regPeriod,
    this.followersMin,
    this.followersMax,
    this.postMin,
    this.postMax,
    this.likeMin,
    this.likeMax,
    this.coinsMin,
    this.coinsMax,
    this.cookieLogin,
    this.verified,
    this.email,
  });

  Map<String, Object?> toMap() {
    return {
      'page': page,
      'pmin': pmin,
      'pmax': pmax,
      'title': title,
      'order_by': orderBy?.value,
      'tag_id[]': tagId,
      'not_tag_id[]': notTagId,
      'public_tag_id[]': publicTagId,
      'not_public_tag_id[]': notPublicTagId,
      'origin[]': origin?.value,
      'not_origin[]': notOrigin,
      'user_id': userId,
      'nsb': nsb,
      'sb': sb,
      'nsb_by_me': nsbByMe,
      'sb_by_me': sbByMe,
      'currency': currency?.value,
      'email_login_data': emailLoginData,
      'email_provider[]': emailProvider,
      'not_email_provider[]': notEmailProvider?.value,
      'parse_same_item_ids': parseSameItemIds,
      'email_type[]': emailType,
      'item_domain': itemDomain,
      'tel': tel?.value,
      'reg': reg,
      'reg_period': regPeriod?.value,
      'followers_min': followersMin,
      'followers_max': followersMax,
      'post_min': postMin,
      'post_max': postMax,
      'like_min': likeMin,
      'like_max': likeMax,
      'coins_min': coinsMin,
      'coins_max': coinsMax,
      'cookie_login': cookieLogin?.value,
      'verified': verified?.value,
      'email': email?.value,
    };
  }
}

