class CategoryBattleNetParams {
  /// The number of the page to display results from.
  final int? page;

  /// Minimal price of account (Inclusive).
  final int? pmin;

  /// Maximum price of account (Inclusive).
  final int? pmax;

  /// The word or words contained in the account title.
  final String? title;
  final OrderBy? orderBy;

  /// List of tag ids (Tag list is available via $1).
  final List<int>? tagId;

  /// List of tag ids that won't be included (Tag list is available via $1).
  final List<int>? notTagId;

  /// List of tag ids (Tag list is available via $1).
  final List<int>? publicTagId;

  /// List of tag ids that won't be included (Tag list is available via $1).
  final List<int>? notPublicTagId;
  final Origin? origin;

  /// List of account origins that won't be included.
  final List<String>? notOrigin;

  /// Search accounts of user.
  final int? userId;

  /// Not sold before.
  final bool? nsb;

  /// Sold before.
  final bool? sb;

  /// Not sold by me before.
  final bool? nsbByMe;

  /// Sold by me before.
  final bool? sbByMe;
  final Currency? currency;

  /// Has email login data.
  final bool? emailLoginData;

  /// Email provider.
  final List<String>? emailProvider;
  final NotEmailProvider? notEmailProvider;

  /// Parse same item ids.
  final bool? parseSameItemIds;

  /// Email type.
  final List<String>? emailType;

  /// Domain of native/autoreg email.
  final String? itemDomain;
  final Eg? eg;

  /// List of games.
  final List<int>? game;

  /// Number of days the account has been offline.
  final int? daybreak;

  /// List of allowed countries.
  final List<String>? country;

  /// List of disallowed countries.
  final List<String>? notCountry;
  final Tel? tel;
  final EditBtag? editBtag;
  final ChangeableFn? changeableFn;
  final RealId? realId;
  final ParentControl? parentControl;
  final NoBans? noBans;

  /// Minimum balance.
  final int? balanceMin;

  /// Maximum balance.
  final int? balanceMax;

  const CategoryBattleNetParams({
    this.page,
    this.pmin,
    this.pmax,
    this.title,
    this.orderBy,
    this.tagId,
    this.notTagId,
    this.publicTagId,
    this.notPublicTagId,
    this.origin,
    this.notOrigin,
    this.userId,
    this.nsb,
    this.sb,
    this.nsbByMe,
    this.sbByMe,
    this.currency,
    this.emailLoginData,
    this.emailProvider,
    this.notEmailProvider,
    this.parseSameItemIds,
    this.emailType,
    this.itemDomain,
    this.eg,
    this.game,
    this.daybreak,
    this.country,
    this.notCountry,
    this.tel,
    this.editBtag,
    this.changeableFn,
    this.realId,
    this.parentControl,
    this.noBans,
    this.balanceMin,
    this.balanceMax,
  });

  Map<String, Object?> toMap() {
    return {
      'page': page,
      'pmin': pmin,
      'pmax': pmax,
      'title': title,
      'order_by': orderBy?.value,
      'tag_id[]': tagId,
      'not_tag_id[]': notTagId,
      'public_tag_id[]': publicTagId,
      'not_public_tag_id[]': notPublicTagId,
      'origin[]': origin?.value,
      'not_origin[]': notOrigin,
      'user_id': userId,
      'nsb': nsb,
      'sb': sb,
      'nsb_by_me': nsbByMe,
      'sb_by_me': sbByMe,
      'currency': currency?.value,
      'email_login_data': emailLoginData,
      'email_provider[]': emailProvider,
      'not_email_provider[]': notEmailProvider?.value,
      'parse_same_item_ids': parseSameItemIds,
      'email_type[]': emailType,
      'item_domain': itemDomain,
      'eg': eg?.value,
      'game[]': game,
      'daybreak': daybreak,
      'country[]': country,
      'not_country[]': notCountry,
      'tel': tel?.value,
      'edit_btag': editBtag?.value,
      'changeable_fn': changeableFn?.value,
      'real_id': realId?.value,
      'parent_control': parentControl?.value,
      'no_bans': noBans?.value,
      'balance_min': balanceMin,
      'balance_max': balanceMax,
    };
  }
}

