class CategoryChatGPTParams {
  /// The number of the page to display results from.
  final int? page;

  /// Minimal price of account (Inclusive).
  final int? pmin;

  /// Maximum price of account (Inclusive).
  final int? pmax;

  /// The word or words contained in the account title.
  final String? title;
  final OrderBy? orderBy;

  /// List of tag ids (Tag list is available via $1).
  final List<int>? tagId;

  /// List of tag ids that won't be included (Tag list is available via $1).
  final List<int>? notTagId;

  /// List of tag ids (Tag list is available via $1).
  final List<int>? publicTagId;

  /// List of tag ids that won't be included (Tag list is available via $1).
  final List<int>? notPublicTagId;
  final Origin? origin;

  /// List of account origins that won't be included.
  final List<String>? notOrigin;

  /// Search accounts of user.
  final int? userId;

  /// Not sold before.
  final bool? nsb;

  /// Sold before.
  final bool? sb;

  /// Not sold by me before.
  final bool? nsbByMe;

  /// Sold by me before.
  final bool? sbByMe;
  final Currency? currency;

  /// Has email login data.
  final bool? emailLoginData;

  /// Email provider.
  final List<String>? emailProvider;
  final NotEmailProvider? notEmailProvider;

  /// Parse same item ids.
  final bool? parseSameItemIds;

  /// Email type.
  final List<String>? emailType;

  /// Domain of native/autoreg email.
  final String? itemDomain;

  /// List of allowed subscriptions.
  final List<String>? subscription;

  /// Length of subscription.
  final int? subscriptionLength;
  final SubscriptionPeriod? subscriptionPeriod;
  final Autorenewal? autorenewal;
  final Tel? tel;
  final Transactions? transactions;

  /// How old is the account.
  final int? reg;
  final RegPeriod? regPeriod;

  /// List of allowed tiers.
  final List<String>? openaiTier;

  /// Minimum OpenAI credit balance.
  final int? openaiBalanceMin;

  /// Maximum OpenAI credit balance.
  final int? openaiBalanceMax;

  const CategoryChatGPTParams({
    this.page,
    this.pmin,
    this.pmax,
    this.title,
    this.orderBy,
    this.tagId,
    this.notTagId,
    this.publicTagId,
    this.notPublicTagId,
    this.origin,
    this.notOrigin,
    this.userId,
    this.nsb,
    this.sb,
    this.nsbByMe,
    this.sbByMe,
    this.currency,
    this.emailLoginData,
    this.emailProvider,
    this.notEmailProvider,
    this.parseSameItemIds,
    this.emailType,
    this.itemDomain,
    this.subscription,
    this.subscriptionLength,
    this.subscriptionPeriod,
    this.autorenewal,
    this.tel,
    this.transactions,
    this.reg,
    this.regPeriod,
    this.openaiTier,
    this.openaiBalanceMin,
    this.openaiBalanceMax,
  });

  Map<String, Object?> toMap() {
    return {
      'page': page,
      'pmin': pmin,
      'pmax': pmax,
      'title': title,
      'order_by': orderBy?.value,
      'tag_id[]': tagId,
      'not_tag_id[]': notTagId,
      'public_tag_id[]': publicTagId,
      'not_public_tag_id[]': notPublicTagId,
      'origin[]': origin?.value,
      'not_origin[]': notOrigin,
      'user_id': userId,
      'nsb': nsb,
      'sb': sb,
      'nsb_by_me': nsbByMe,
      'sb_by_me': sbByMe,
      'currency': currency?.value,
      'email_login_data': emailLoginData,
      'email_provider[]': emailProvider,
      'not_email_provider[]': notEmailProvider?.value,
      'parse_same_item_ids': parseSameItemIds,
      'email_type[]': emailType,
      'item_domain': itemDomain,
      'subscription[]': subscription,
      'subscription_length': subscriptionLength,
      'subscription_period': subscriptionPeriod?.value,
      'autorenewal': autorenewal?.value,
      'tel': tel?.value,
      'transactions': transactions?.value,
      'reg': reg,
      'reg_period': regPeriod?.value,
      'openai_tier[]': openaiTier,
      'openai_balance_min': openaiBalanceMin,
      'openai_balance_max': openaiBalanceMax,
    };
  }
}

