class PaymentsInvoiceCreateBody {
  final Currency currency;

  /// Invoice amount.
  final num amount;

  /// Payment ID in your system (must be unique within the merchant / invoices).
  final String paymentId;

  /// Comment to the invoice.
  final String comment;

  /// URL to redirect to after successful payment.
  final String urlSuccess;

  /// Callback url.
  final String? urlCallback;

  /// Merchant ID.
  final int merchantId;

  /// Telegram User ID for which the invoice was created.
  final int? requiredTelegramId;

  /// Telegram Username (including @) for which the invoice was created (if any).
  final String? requiredTelegramUsername;

  /// Invoice lifetime.. Default: 3600.
  final num? lifetime;

  /// Additional information for you.
  final String? additionalData;

  /// Create a test invoice.
  final bool? isTest;

  const PaymentsInvoiceCreateBody({
    required this.currency,
    required this.amount,
    required this.paymentId,
    required this.comment,
    required this.urlSuccess,
    this.urlCallback,
    required this.merchantId,
    this.requiredTelegramId,
    this.requiredTelegramUsername,
    this.lifetime = 3600,
    this.additionalData,
    this.isTest,
  });

  Map<String, Object?> toMap() {
    return {
      'currency': currency.value,
      'amount': amount,
      'payment_id': paymentId,
      'comment': comment,
      'url_success': urlSuccess,
      'url_callback': urlCallback,
      'merchant_id': merchantId,
      'required_telegram_id': requiredTelegramId,
      'required_telegram_username': requiredTelegramUsername,
      'lifetime': lifetime,
