class PaymentsTransferBody {
  /// User id of receiver. If $1 specified, $1 is not required.
  final int? userId;

  /// Username of receiver. If $1 specified, $1 is not required.
  final String? username;

  /// Amount to send in your currency.
  final int amount;
  final Currency currency;

  /// Transfer comment.
  final String? comment;

  /// Is the deal happening on Telegram?.
  final bool? telegramDeal;

  /// Telegram username of the user you are dialoguing with.
  final String? telegramUsername;

  /// Hold transfer or not.
  final bool? transferHold;

  /// Hold length value.
  final int? holdLengthValue;
  final HoldLengthOption? holdLengthOption;

  const PaymentsTransferBody({
    this.userId,
    this.username,
    required this.amount,
    required this.currency,
    this.comment,
    this.telegramDeal,
    this.telegramUsername,
    this.transferHold,
    this.holdLengthValue,
    this.holdLengthOption,
  });

  Map<String, Object?> toMap() {
    return {
      'user_id': userId,
      'username': username,
      'amount': amount,
      'currency': currency.value,
      'comment': comment,
      'telegram_deal': telegramDeal,
      'telegram_username': telegramUsername,
      'transfer_hold': transferHold,
      'hold_length_value': holdLengthValue,
      'hold_length_option': holdLengthOption?.value,
    };
  }
}

