  final Currency? currency;

  /// The number of the page to display results from.
  final int? page;

  /// Id of the operation from which the result begins.
  final int? operationIdLt;

  /// Username of user, which receive money from you.
  final String? receiver;

  /// Username of user, which sent money to you.
  final String? sender;

  /// Returns payments that are done via API.
  final bool? isApi;

  /// Start date of operation (RFC 3339 date format).
  final String? startDate;

  /// End date of operation (RFC 3339 date format).
  final String? endDate;

  /// Wallet, which used for money payouts.
  final String? wallet;

  /// Comment for money transfers.
  final String? comment;

  /// Display hold operations.
  final bool? isHold;

  /// Display payment stats for selected period (outgoing value, incoming value).
  final bool? showPaymentStats;

  const PaymentsHistoryParams({
    this.type,
    this.pmin,
    this.pmax,
    this.currency,
    this.page,
    this.operationIdLt,
    this.receiver,
    this.sender,
    this.isApi,
    this.startDate,
    this.endDate,
    this.wallet,
    this.comment,
    this.isHold,
    this.showPaymentStats,
  });

  Map<String, Object?> toMap() {
    return {
      'type': type?.value,
      'pmin': pmin,
      'pmax': pmax,
      'currency': currency?.value,
      'page': page,
      'operation_id_lt': operationIdLt,
      'receiver': receiver,
      'sender': sender,
      'is_api': isApi,
      'startDate': startDate,
      'endDate': endDate,
      'wallet': wallet,
      'comment': comment,
      'is_hold': isHold,
      'show_payment_stats': showPaymentStats,
    };
  }
}

